import { Input } from '@chakra-ui/react'

export const UpdateTodo = (props) => {
    const { incompleteTodos, onClickUpdate } = props;

    return (
        <div>
            <ul>
            {incompleteTodos.map((todo, index) => (
            <li key={todo}>
                <Input placeholder='Basic usage' />
            </li>
                )
            )}
            </ul>
        </div>
    )
}
